Certain mechanics done \"differently\" due to missing sniff info (like phases, spells etc)","-- These should NOT be required for the main content to work and are optional","","-- Phases","DELETE FROM `phase_area` WHERE `PhaseId` IN (50004, 50005);","INSERT INTO `phase_area` VALUES","(40, 50004, 'Westfall - Furlbrows 1 - Defias Brotherhood'),","(40, 50005, 'Westfall - Furlbrows 2 - Return of the Defias (Vanessa)');","","-- Phase Conditions","DELETE FROM `conditions` WHERE `SourceTypeOrReferenceId` = 26 AND `SourceGroup` IN (50004, 50005);","INSERT INTO `conditions` VALUES","-- Phase 50004 allows the OLD Furlbrows npcs to be again visible for the old quests","-- This includes ALL the OLD Defias mobs around westfall.","-- They will be gone after the quest The Defias Brotherhood is completed","-- At that point the new quest line can be started","('26', '50004', '0', '0', '0', '47', '0', '166', '64', '0', '', '1', '0', '0', '', 'Westfall - Add phase 50004 if 166 IS NOT rewarded'),","-- Phase 50005 is the phase for the new/post Cata storyline","-- It starts after the quest The Defias Brotherhood","('26', '50005', '0', '0', '0', '47', '0', '166', '64', '0', '', '0', '0', '0', '', 'Westfall - Add phase 50005 if 166 IS rewarded'),","('26', '50005', '0', '0', '0', '47', '0', '26322', '74', '0', '', '1', '0', '0', '', 'Westfall - Add phase 50005 if 26322 IS NOT in progress, complete or rewarded');","","INSERT INTO `conditions` (`SourceTypeOrReferenceId`, `SourceGroup`, `SourceEntry`, `SourceId`, `ElseGroup`, `ConditionTypeOrReference`, `ConditionTarget`, `ConditionValue1`, `ConditionValue2`, `ConditionValue3`, `ConditionStringValue1`, `NegativeCondition`, `Comment`) VALUES ","(26, 50005, 40, 0, 1, 47, 0, 26761, 64, 0, '', 0, 'Player has quest 26761 rewarded');","","-- Reactivating old/deprecated quests for Deadmines","-- These start in various places","DELETE FROM `disables` WHERE `entry` IN (167,168) AND `sourceType` = 1; -- quest source","","DELETE FROM `creature_queststarter` WHERE `quest` IN (167,168);","INSERT INTO `creature_queststarter` (`id`, `quest`, `VerifiedBuild`) VALUES ","(656, 167, 0),","(656, 168, 0);","","DELETE FROM `creature_questender` WHERE `quest` IN (167,168);","INSERT INTO `creature_questender` (`id`, `quest`, `VerifiedBuild`) VALUES","(656, 167, 0),","(656, 168, 0);","","-- Reactivating old/deprecated quests in Westfall","DELETE FROM `disables` WHERE `entry` IN (9, 22, 36, 64, 109, 151, 103) AND `sourceType` = 1; -- quest source","DELETE FROM `creature_queststarter` WHERE `quest` IN (9, 22, 36, 109, 64, 151, 103);","INSERT INTO `creature_queststarter` (`id`, `quest`, `VerifiedBuild`) VALUES ","('900000', '64', '0'),","('900001', '36', '0'),","('900001', '151', '0'),","('900000', '109', '0'),","('392', '103', '0'),","('235', '22', '0'),","('233', '9', '0');","","DELETE FROM `creature_questender` WHERE `quest` IN (9, 22, 36, 109, 64, 151, 184, 103);","INSERT INTO `creature_questender` (`id`, `quest`, `VerifiedBuild`) VALUES ","('900000', '64', '0'),","('900000', '184', '0'),","('235', '36', '0'),","('900001', '151', '0'),","('234', '109', '0'),","('392', '103', '0'),","('235', '22', '0'),","('233', '9', '0');","","","-- Quest Templates","UPDATE `quest_template` SET `ContentTuningID` = '6', `Expansion` = '0' WHERE `ID` IN (9, 22, 36, 109, 64, 103, 151,167,168);","DELETE FROM `quest_template_addon` WHERE `ID` IN (109);","INSERT INTO `quest_template_addon` (`ID`, `PrevQuestID`) VALUES","(109, 64);","","","-- Reactivating old/deprecated quests in Sentinel Hill","DELETE FROM `disables` WHERE (`sourceType` = '1') and `entry` IN (12, 13, 14, 102, 153, 65, 132, 135, 141, 142, 155, 166);","DELETE FROM `disables` WHERE (`sourceType` = '1') and `entry` IN (6181, 6281);","","-- Quest Templates","UPDATE `quest_template` SET `ContentTuningID` = '6', `Expansion` = 0, `AllowableRaces` = 18446744073709551615 WHERE `ID` IN (12, 13, 14, 102, 153, 65, 132, 135, 141, 142, 155, 166, 6181, 6281);","","-- Creature Quest Relations","DELETE