ases, spells etc)\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e These should NOT be required for the main content to work and are optional\u003c/span\u003e","","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e Phases\u003c/span\u003e","\u003cspan class=\"pl-k\"\u003eDELETE\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eFROM\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003ephase_area\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eWHERE\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003ePhaseId\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eIN\u003c/span\u003e (\u003cspan class=\"pl-c1\"\u003e50004\u003c/span\u003e, \u003cspan class=\"pl-c1\"\u003e50005\u003c/span\u003e);","\u003cspan class=\"pl-k\"\u003eINSERT INTO\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003ephase_area\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eVALUES\u003c/span\u003e","(\u003cspan class=\"pl-c1\"\u003e40\u003c/span\u003e, \u003cspan class=\"pl-c1\"\u003e50004\u003c/span\u003e, \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e\u0026#39;\u003c/span\u003eWestfall - Furlbrows 1 - Defias Brotherhood\u003cspan class=\"pl-pds\"\u003e\u0026#39;\u003c/span\u003e\u003c/span\u003e),","(\u003cspan class=\"pl-c1\"\u003e40\u003c/span\u003e, \u003cspan class=\"pl-c1\"\u003e50005\u003c/span\u003e, \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e\u0026#39;\u003c/span\u003eWestfall - Furlbrows 2 - Return of the Defias (Vanessa)\u003cspan class=\"pl-pds\"\u003e\u0026#39;\u003c/span\u003e\u003c/span\u003e);","","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e Phase Conditions\u003c/span\u003e","\u003cspan class=\"pl-k\"\u003eDELETE\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eFROM\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003econditions\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eWHERE\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003eSourceTypeOrReferenceId\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003e=\u003c/span\u003e \u003cspan class=\"pl-c1\"\u003e26\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eAND\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003eSourceGroup\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eIN\u003c/span\u003e (\u003cspan class=\"pl-c1\"\u003e50004\u003c/span\u003e, \u003cspan class=\"pl-c1\"\u003e50005\u003c/span\u003e);","\u003cspan class=\"pl-k\"\u003eINSERT INTO\u003c/span\u003e \u003cspan class=\"pl-s\"\u003e\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003econditions\u003cspan class=\"pl-pds\"\u003e`\u003c/span\u003e\u003c/span\u003e \u003cspan class=\"pl-k\"\u003eVALUES\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e Phase 50004 allows the OLD Furlbrows npcs to be again visible for the old quests\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e This includes ALL the OLD Defias mobs around westfall.\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e They will be gone after the quest The Defias Brotherhood is completed\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e--\u003c/span\u003e At that point the new quest line can be started\u003c/span\u003e","(\u003cspan class=\"pl-s\"\u003e\u003cspan class=